using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();

var dataDir = Path.Combine(builder.Environment.ContentRootPath, "Data");
var dataPath = Path.Combine(dataDir, "tickets.csv");
var modelPath = Path.Combine(dataDir, "ticket-model.zip");

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train the model at startup before handling requests
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
trainer.TrainAndSave(dataPath, modelPath);

app.MapControllers();
app.Run();

